29	      if (path === '.claudinite-checks.json' && !(path in tree)) return JSON.stringify({ maintenance: { delivery } });
30	      return path in tree ? tree[path] : null;
31	    },
32	    ensureBranch: async (_repo, branch, from) => { state.branchCreated = { branch, from }; },
33	    commit: async (_repo, branch, fileList, message) => { state.commits.push({ branch, files: fileList, message }); },
