1	// Migration application — the fleet-wide APPLY pass (phase 1 of the daily
2	// maintenance routine, run BEFORE the pack tasks). Migrations-owned: basics
3	// baselining no longer carries the "apply migrations" step. See migrations/README.md
4	// and routines/auto-all-repos-maintenance.md.
5	//
6	// What it does: for every member the routine hands it, compute the member's pending
7	// migration writes — the same three write ops the local applier runs (file aliases,
8	// materialize, rewrite; registry.mjs) — against the member's target branch and land
9	// them. Templates are read from the canon checkout this runs in (the parent of
10	// migrations/); member reads/writes go through the injected `io` (below). Idempotent:
11	// a member already on the canonical shape stages nothing and gets no commit.
12	//
13	// Delivery honors the member's `.claudinite-checks.json` `maintenance.delivery`
14	// (default `push`): `push` commits to the default branch; `pr` commits to the stable
15	// `claudinite/maintenance` branch and ensures its one open PR; anything else commits
16	// nothing and opens an issue naming it.
17	//
18	// The pr lane regenerates, never reconciles (#332): the desired end-state is
19	// always computed against the DEFAULT branch (the truth being migrated), never
20	// the maintenance branch's own stale copy; writes the branch already carries are
21	// dropped so quiet nights add no commits; and each run first refreshes the
22	// branch from base (io.updateBranchFromBase, optional — a conflict is noted for
23	// the owner, never resolved here) so a weeks-open PR doesn't merge stale-based
24	// content.
25	//
26	// GitHub I/O is a small injected `io` object whose methods map 1:1 to the GitHub MCP
27	// tools the orchestrator drives — there is NO REST client here and no token:
28	//   io.getDefaultBranch(repo)                 -> string | null   (get repo)
29	//   io.read(repo, path[, ref])                -> string | null   (get_file_contents)
30	//   io.ensureBranch(repo, branch, fromBranch)                    (create_branch; idempotent)
31	//   io.commit(repo, branch, files, message)                      (push_files — files:[{path,content}])
32	//   io.remove(repo, branch, path, message)    -> boolean         (delete_file; tolerates absent)
33	//   io.hasOpenPr(repo, headBranch)            -> boolean         (list_pull_requests)
34	//   io.openPr(repo, head, base, title, body)                     (create_pull_request)
35	//   io.openIssue(repo, title, body)                              (issue_write create)
36	//   io.updateBranchFromBase(repo, headBranch)  [optional]        (update_pull_request_branch
37	//                                                on its open PR; throws on conflict)
38	// The writes land as one `commit` (push_files); a rare file-move's delete follows via
39	// `remove` (a separate commit — MCP has no atomic multi-file+delete, and no active
40	// migration produces a delete). `applyToRepos` returns the migration ids it applied
41	// this cycle; the orchestrator hands that set to the retire pass as its quiescence
42	// evidence (a migration touched this cycle is never retired this cycle).
43	
44	import { existsSync, readFileSync } from 'node:fs';
45	import { dirname, join } from 'node:path';
46	import { fileURLToPath } from 'node:url';
47	import { applyFileAliases, applyMaterializations, applyRewrites } from './registry.mjs';
48	
49	const MAINT_BRANCH = 'claudinite/maintenance';
50	const canonRoot = dirname(dirname(fileURLToPath(import.meta.url))); // the checkout ships the templates
51	const readTemplate = (p) => (existsSync(join(canonRoot, p)) ? readFileSync(join(canonRoot, p), 'utf8') : null);
52	
53	// Stage a member's whole pending migration write-set in memory (reading `branch`),
54	// so it commits as ONE commit. Staged-aware readers let a later op see an earlier
55	// op's write. Returns { files, deletes, ids } or null when nothing changed.
56	async function stageMemberWrites(io, fullName, branch, migrations) {
57	  const files = new Map(); const deletes = new Set(); const ids = new Set();
58	  const read = async (p) => {
59	    if (files.has(p)) return files.get(p);
60	    if (deletes.has(p)) return null;
61	    return io.read(fullName, p, branch);
62	  };
63	  const exists = async (p) => (await read(p)) !== null;
64	  const write = (p, c) => { files.set(p, c); deletes.delete(p); };
65	  const move = async (from, to) => {
66	    const content = await read(from);
67	    if (content == null) return;
68	    files.set(to, content); files.delete(from); deletes.add(from);
69	  };
70	  for (const m of migrations) {
71	    const a = await applyFileAliases(m, { exists, move });
72	    const mat = await applyMaterializations(m, { readTemplate, read, write });
73	    const rw = await applyRewrites(m, { read, write });
74	    if (a.length || mat.length || rw.length) ids.add(m.id);
75	  }
76	  return (files.size || deletes.size) ? { files, deletes, ids } : null;
77	}
78	
79	// Apply pending migrations to one repo the routine handed us; returns the migration
80	// ids applied (empty when nothing was pending). Honors the repo's delivery preference.
81	export async function applyToRepo(io, fullName, migrations) {
82	  const defaultBranch = await io.getDefaultBranch(fullName);
83	  if (!defaultBranch) return { ids: [], note: `${fullName}: unreadable` };
84	  const cfg = await io.read(fullName, '.claudinite-checks.json');
85	  let delivery = 'push';
86	  try { delivery = JSON.parse(cfg ?? '{}')?.maintenance?.delivery ?? 'push'; } catch { delivery = 'push'; }
87	
88	  if (delivery !== 'push' && delivery !== 'pr') {
89	    await io.openIssue(
90	      fullName,
91	      'Claudinite maintenance: unrecognized delivery preference',
92	      `\`.claudinite-checks.json\` sets \`maintenance.delivery: "${delivery}"\`, which is neither \`push\` nor \`pr\`. `
93	        + 'Migrations were not applied this run. Set it to `push` or `pr`.',
94	    );
95	    return { ids: [], note: `${fullName}: unrecognized delivery "${delivery}" — opened an issue, applied nothing` };
96	  }
97	
98	  const branch = delivery === 'pr' ? MAINT_BRANCH : defaultBranch;
99	  const notes = [];
100	  if (delivery === 'pr') {
101	    await io.ensureBranch(fullName, MAINT_BRANCH, defaultBranch);
102	    // Refresh the branch from base BEFORE staging, so the diff below sees the
103	    // branch's true tip and the eventual merge isn't stale-based (#332). A
104	    // conflict is the owner's to see, never resolved here.
105	    if (io.updateBranchFromBase && (await io.hasOpenPr(fullName, MAINT_BRANCH))) {
106	      try { await io.updateBranchFromBase(fullName, MAINT_BRANCH); }
107	      catch (e) { notes.push(`maintenance branch could not update from base: ${e.message}`); }
108	    }
109	  }
110	
111	  // Desired end-state is ALWAYS computed against the default branch — the truth
112	  // being migrated — never the maintenance branch's own copy (#332).
113	  const staged = await stageMemberWrites(io, fullName, defaultBranch, migrations);
114	  if (!staged) return { ids: [], note: notes.length ? `${fullName}: ${notes.join('; ')}` : undefined };
115	
116	  let files = [...staged.files].map(([path, content]) => ({ path, content }));
117	  let deletes = [...staged.deletes];
118	  if (delivery === 'pr') {
119	    // Drop writes the branch already carries, so an unmerged PR doesn't collect
120	    // an identical commit every night.
121	    const pending = [];
122	    for (const f of files) {
123	      if ((await io.read(fullName, f.path, MAINT_BRANCH)) !== f.content) pending.push(f);
124	    }
125	    files = pending;
126	    const pendingDeletes = [];
127	    for (const path of deletes) {
128	      if ((await io.read(fullName, path, MAINT_BRANCH)) !== null) pendingDeletes.push(path);
129	    }
130	    deletes = pendingDeletes;
131	    if (!files.length && !deletes.length) {
132	      return { ids: [], note: notes.length ? `${fullName}: ${notes.join('; ')}` : undefined };
133	    }
134	  }
135	
136	  if (files.length) await io.commit(fullName, branch, files, 'Apply Claudinite migrations');
137	  for (const path of deletes) {
138	    await io.remove(fullName, branch, path, `Apply Claudinite migrations: remove ${path}`);
139	  }
140	  if (delivery === 'pr' && !(await io.hasOpenPr(fullName, MAINT_BRANCH))) {
141	    await io.openPr(
142	      fullName, MAINT_BRANCH, defaultBranch, 'Claudinite maintenance',
143	      'Automated Claudinite maintenance (migrations + baselining). Amended in place each run; never auto-merged.',
144	    );
145	  }
146	  notes.unshift(`applied ${[...staged.ids].join(', ')} (${delivery})`);
147	  return { ids: [...staged.ids], note: `${fullName}: ${notes.join('; ')}` };
148	}
149	
150	// Apply pending migrations to every repo the routine handed us. A repo that throws is
151	// isolated — its error is noted and the rest still run. Returns the union of applied
152	// ids (this cycle's quiescence evidence) + notes. The orchestrator (which loads the
153	// migration set via registry.mjs and supplies the MCP-backed `io`) calls this, then
154	// passes `appliedIds` straight to the retire pass — no intermediate file needed.
155	export async function applyToRepos(io, fullNames, migrations) {
156	  const appliedIds = new Set(); const notes = [];
157	  for (const fullName of fullNames) {
158	    try {
159	      const { ids, note } = await applyToRepo(io, fullName, migrations);
160	      ids.forEach((id) => appliedIds.add(id));
161	      if (note) notes.push(note);
162	    } catch (e) { notes.push(`${fullName}: apply failed (${e.message})`); }
163	  }
164	  return { appliedIds: [...appliedIds], notes };
165	}
166

1	// Migration finalization — the fleet-wide RETIRE pass (phase 3 of the daily
2	// maintenance routine, run after the pack tasks settle). Migrations-owned:
3	// baselining carries no migration logic. See migrations/README.md and
4	// routines/auto-all-repos-maintenance.md.
5	//
6	// What it does: over the repos the routine hands it, probe every migration's
7	// `legacyPresent`, and auto-retire any migration the whole fleet has left behind —
8	// deleting the files it relocated into the consumers (retireDeletesFromHome) FIRST,
9	// then the record itself. Retirement acts on the CANON repo — the SAME repo the
10	// migrations are loaded from (migrations/active_migrations/): there is no separate
11	// "home repo" to discover. The orchestrator names that repo (a known constant) when
12	// it loads the migrations and again here; loading and retiring a migration are one
13	// place, not two processes of discovery.
14	//
15	// The QUIESCENCE guard (why this runs AFTER, and separate from, apply): a migration
16	// is retired only after a full nightly cycle in which the apply pass touched it on NO
17	// repo. The apply pass returns the ids it applied this cycle; the orchestrator hands
18	// that set here as `appliedThisCycle`, and retirableMigrations refuses to retire
19	// anything in it — so the cycle that converges the last member can never also retire.
20	// If that evidence is ABSENT (`null` — the apply pass didn't run this cycle)
21	// quiescence is unproven, so this pass retires nothing — retirement is irreversible,
22	// and a missing apply signal must never be read as "the fleet is quiet".
23	//
24	// GitHub I/O is the same small injected `io` object the apply pass takes (each method
25	// a GitHub MCP tool) — there is NO REST client here and no token:
26	//   io.read(repo, path)          -> string | null   (get_file_contents; 404 -> null)
27	//   io.getDefaultBranch(repo)    -> string | null   (get repo)
28	//   io.ensureBranch(repo, branch, fromBranch)        (create_branch; idempotent)
29	//   io.remove(repo, branch, path, message) -> boolean (delete_file; tolerates absent)
30	//   io.hasOpenPr(repo, headBranch) -> boolean        (list_pull_requests)
31	//   io.openPr(repo, head, base, title, body)         (create_pull_request)
32	// Read-only toward every repo except the canon repo (its own). Retirement is NEVER
33	// pushed straight to the canon's default branch: an irreversible delete that strands
34	// an inline reference — a barriers `except` entry, a doc link, a test assertion — would
35	// break the canon's own CI, which is exactly how a past auto-retirement took `main` red
36	// (a 'sweep' can't fix it either: part of the footprint is test-file assertions no
37	// deterministic pass should rewrite). Instead the pass stages every delete on a stable
38	// retire branch and opens ONE PR (never auto-merged), so the canon's own checks — the
39	// same `barrier`, `reference-integrity`, and test suite — VALIDATE the retirement before
40	// it can land: a clean retirement is a green, mergeable PR; a stranding one is a red PR
41	// held for a human to clean the references it exposed. `main` never goes red from a
42	// retirement.
43	
44	import { retirableMigrations, MIGRATIONS_SUBDIR } from './registry.mjs';
45	
46	// Retirement is delivered like the apply pass's own writes — a stable branch + one open
47	// PR, never auto-merged — so the canon's CI gates the irreversible deletes.
48	const RETIRE_BRANCH = 'claudinite/retire-migrations';
49	const RETIRE_PR_BODY = [
50	  'Automated migration retirement, proposed by the fleet daily maintenance retire pass.',
51	  '',
52	  'Each retired migration deletes its record and the now-unused canon files it had',
53	  'vendored into the consumers. This is **irreversible**, so it is delivered as a PR',
54	  'rather than pushed to the default branch: the canon\'s own CI (barriers,',
55	  'reference-integrity, tests) validates that the deletion strands no inline reference',
56	  'before it can land. A green run is safe to merge; a red run means the retirement',
57	  'would break the canon — clean up the references it flags first. Never auto-merged;',
58	  'amended in place each run.',
59	].join('\n');
60	
61	// Retire one fully-applied migration: stage the deletion of any files it relocated into
62	// the consumers (retireDeletesFromHome) FIRST, then the record itself — so a partial
63	// failure leaves the record to retry the rest next cycle (each delete tolerates an
64	// already-gone file). Staged onto `branch` (the retire branch, NOT the default branch),
65	// so the whole deletion rides one CI-gated PR rather than landing on the canon directly.
66	export async function retireMigration(io, canonRepo, branch, m) {
67	  const relocatedFiles = m.retireDeletesFromHome ?? [];
68	  for (const p of relocatedFiles) {
69	    await io.remove(canonRepo, branch, p, `Retire migration ${m.id}: remove ${p} — vendored into every consumer, unused in the canon`);
70	  }
71	  const record = `migrations/${MIGRATIONS_SUBDIR}/${m.file}`;
72	  await io.remove(canonRepo, branch, record,
73	    `Retire migration ${m.id}: fully applied and quiet across the fleet (0 repos on the legacy shape, 0 applications this cycle)`);
74	  return `staged retirement of ${m.id} on the retire PR — ${record}${relocatedFiles.length ? ` + ${relocatedFiles.length} canon file(s)` : ''}`;
75	}
76	
77	// Probe every covered repo for each migration's legacy shape, then retire the ones
78	// the fleet has left behind AND the apply pass left untouched this cycle. A probe
79	// error counts as pending (never "clean"), so an API hiccup only ever delays a
80	// retirement, never triggers a premature one. `appliedThisCycle` is the Set of ids
81	// the apply pass applied this run (passed in memory), or `null` when apply didn't run.
82	export async function runRetirement(io, canonRepo, migrations, covered, unknownCount, today, appliedThisCycle) {
83	  if (migrations.length === 0) return [];
84	  if (appliedThisCycle === null) {
85	    return ['no apply evidence from the apply pass this cycle — retiring nothing (quiescence unproven)'];
86	  }
87	  const lines = [];
88	  const notes = [];
89	  const pending = new Map(migrations.map((m) => [m.id, 0]));
90	  for (const fullName of covered) {
91	    const exists = async (path) => (await io.read(fullName, path)) !== null;
92	    const read = (path) => io.read(fullName, path);
93	    for (const m of migrations) {
94	      let stillLegacy;
95	      try {
96	        stillLegacy = await m.legacyPresent(exists, read);
97	      } catch (e) {
98	        stillLegacy = true;
99	        notes.push(`${m.id}: probe on ${fullName} errored (${e.message}) — counted pending`);
100	      }
101	      if (stillLegacy) pending.set(m.id, pending.get(m.id) + 1);
102	    }
103	  }
104	  for (const m of migrations) {
105	    const appliedNote = appliedThisCycle.has(m.id) ? ', applied this cycle' : '';
106	    lines.push(`${m.id} — ${pending.get(m.id)} repo(s) still on the legacy shape${appliedNote}`);
107	  }
108	  const retirable = retirableMigrations(migrations, { pending, unknownCount, today, appliedThisCycle });
109	  if (retirable.length) {
110	    const defaultBranch = await io.getDefaultBranch(canonRepo);
111	    await io.ensureBranch(canonRepo, RETIRE_BRANCH, defaultBranch);
112	    let staged = false;
113	    for (const m of retirable) {
114	      try {
115	        lines.push(await retireMigration(io, canonRepo, RETIRE_BRANCH, m));
116	        staged = true;
117	      } catch (e) {
118	        lines.push(`could not stage retirement of ${m.id}: ${e.message} — the maintenance session needs Contents write on ${canonRepo}`);
119	      }
120	    }
121	    // One persistent PR, amended in place across runs and never auto-merged: the canon's
122	    // own CI decides whether the retirement is reference-safe to land.
123	    if (staged && !(await io.hasOpenPr(canonRepo, RETIRE_BRANCH))) {
124	      try {
125	        await io.openPr(canonRepo, RETIRE_BRANCH, defaultBranch, 'Claudinite: retire converged migrations', RETIRE_PR_BODY);
126	      } catch (e) {
127	        lines.push(`staged retirement on ${RETIRE_BRANCH} but could not open its PR: ${e.message}`);
128	      }
129	    }
130	  }
131	  return [...lines, ...notes];
